"""
Measure-by-measure MusicXML diagnostic comparison.

Compares ground truth and output MusicXML with structural awareness:
- Per-measure, per-staff comparison (not flat sequence)
- Voice-agnostic matching (ignores voice numbering differences)
- Coverage detection (only scores overlapping measures)
- Error pattern classification (octave, accidental, step, rhythm, wild)

Usage:
    python -m validation.diagnose_musicxml <ground_truth.xml> <output.musicxml>
"""

import sys
import xml.etree.ElementTree as ET
from dataclasses import dataclass, field
from difflib import SequenceMatcher


@dataclass
class NoteInfo:
    pitch: str  # "C4", "D#5", "rest"
    note_type: str  # "quarter", "eighth."
    is_chord: bool = False

    def key(self) -> str:
        return f"{self.pitch}:{self.note_type}"


@dataclass
class MeasureNotes:
    measure_num: int
    notes_by_staff: dict[int, list[NoteInfo]] = field(default_factory=dict)


@dataclass
class ErrorInfo:
    measure: int
    staff: int
    category: str  # "missing", "extra", "octave", "accidental", "step", "rhythm",
    # "rest_note_swap", "cross_staff", "far_pitch"
    detail: str


def _parse_pitch(pitch_elem: ET.Element, ns: str) -> str:
    step = pitch_elem.find(f"{ns}step")
    octave = pitch_elem.find(f"{ns}octave")
    alter = pitch_elem.find(f"{ns}alter")
    step_text = step.text if step is not None else "?"
    octave_text = octave.text if octave is not None else "?"
    alter_text = ""
    if alter is not None:
        a = int(float(alter.text))  # type: ignore[arg-type]
        if a == 1:
            alter_text = "#"
        elif a == -1:
            alter_text = "b"
        elif a == 2:
            alter_text = "##"
        elif a == -2:
            alter_text = "bb"
    return f"{step_text}{alter_text}{octave_text}"


def extract_measures(xml_path: str) -> list[MeasureNotes]:
    """Extract notes grouped by measure and staff from a MusicXML file."""
    tree = ET.parse(xml_path)  # noqa: S314
    root = tree.getroot()

    ns = ""
    if root.tag.startswith("{"):
        ns = root.tag.split("}")[0] + "}"

    measures: dict[int, MeasureNotes] = {}

    for part in root.iter(f"{ns}part"):
        for measure_elem in part.iter(f"{ns}measure"):
            num_str = measure_elem.get("number", "0")
            try:
                num = int(num_str)

                num = int(num_str)
            except ValueError:
                # Some MusicXML files use non-numeric measure numbers like "X1"
                num = int("".join(c for c in num_str if c.isdigit()) or "0")

            if num not in measures:
                measures[num] = MeasureNotes(measure_num=num)

            for note_elem in measure_elem.iter(f"{ns}note"):
                # Skip grace notes
                if note_elem.find(f"{ns}grace") is not None:
                    continue

                type_elem = note_elem.find(f"{ns}type")
                note_type: str = type_elem.text if type_elem is not None and type_elem.text else "?"

                dots = len(note_elem.findall(f"{ns}dot"))
                if dots == 1:
                    note_type += "."
                elif dots == 2:
                    note_type += ".."

                staff_elem = note_elem.find(f"{ns}staff")
                staff_num = (
                    int(staff_elem.text) if staff_elem is not None and staff_elem.text else 1
                )

                is_chord = note_elem.find(f"{ns}chord") is not None

                if note_elem.find(f"{ns}rest") is not None:
                    pitch = "rest"
                else:
                    pitch_elem = note_elem.find(f"{ns}pitch")
                    if pitch_elem is not None:
                        pitch = _parse_pitch(pitch_elem, ns)
                    else:
                        continue

                note = NoteInfo(pitch=pitch, note_type=note_type, is_chord=is_chord)
                if staff_num not in measures[num].notes_by_staff:
                    measures[num].notes_by_staff[staff_num] = []
                measures[num].notes_by_staff[staff_num].append(note)

    return [measures[k] for k in sorted(measures.keys())]


def _split_pitch(pitch_str: str) -> tuple[str, str, str]:
    """Split 'C#4' into ('C', '#', '4'). Returns (letter, accidental, octave)."""
    if pitch_str == "rest":
        return ("rest", "", "")
    letter = pitch_str[0]
    rest = pitch_str[1:]
    accidental = ""
    for acc in ("##", "bb", "#", "b"):
        if rest.startswith(acc):
            accidental = acc
            rest = rest[len(acc) :]
            break
    return (letter, accidental, rest)


# Semitone values for pitch comparison
_NOTE_SEMITONES = {"C": 0, "D": 2, "E": 4, "F": 5, "G": 7, "A": 9, "B": 11}
_ACC_SEMITONES = {"": 0, "#": 1, "b": -1, "##": 2, "bb": -2}


def _pitch_to_midi(pitch_str: str) -> int | None:
    """Convert pitch string to MIDI-like number for interval comparison."""
    if pitch_str == "rest":
        return None
    letter, acc, octave = _split_pitch(pitch_str)
    if letter not in _NOTE_SEMITONES or octave == "" or not octave.isdigit():
        return None
    return int(octave) * 12 + _NOTE_SEMITONES[letter] + _ACC_SEMITONES.get(acc, 0)


def classify_substitution(  # noqa: PLR0911
    gt_pitch: str, out_pitch: str, gt_type: str, out_type: str
) -> str:
    """Classify a substitution error into a category."""
    pitch_same = gt_pitch == out_pitch
    type_same = gt_type == out_type

    if pitch_same:
        return "match" if type_same else "rhythm"

    gt_letter, gt_acc, gt_oct = _split_pitch(gt_pitch)
    out_letter, out_acc, out_oct = _split_pitch(out_pitch)

    # Rest vs note
    if gt_pitch == "rest" or out_pitch == "rest":
        return "rest_note_swap"

    # Same letter checks
    if gt_letter == out_letter:
        if gt_acc == out_acc and gt_oct != out_oct:
            return "octave"
        if gt_oct == out_oct and gt_acc != out_acc:
            gt_midi = _pitch_to_midi(gt_pitch)
            out_midi = _pitch_to_midi(out_pitch)

            if gt_midi is not None and out_midi is not None and gt_midi == out_midi:
                return "enharmonic"
            return "accidental"

    # Step error: adjacent semitone (within 2 semitones)
    gt_midi = _pitch_to_midi(gt_pitch)
    out_midi = _pitch_to_midi(out_pitch)
    if gt_midi is not None and out_midi is not None and abs(gt_midi - out_midi) <= 2:
        return "step"

    # Cross-staff: large interval (>= 12 semitones = octave+) likely from wrong staff
    if gt_midi is not None and out_midi is not None and abs(gt_midi - out_midi) >= 12:
        return "cross_staff"

    return "far_pitch"


def compare_measure_staff(
    gt_notes: list[NoteInfo],
    out_notes: list[NoteInfo],
    measure_num: int,
    staff_num: int,
) -> list[ErrorInfo]:
    """Compare notes for one measure+staff, voice-agnostic."""
    # Sort by pitch then type for consistent ordering (voice-agnostic)
    gt_keys = sorted([n.key() for n in gt_notes])
    out_keys = sorted([n.key() for n in out_notes])

    if gt_keys == out_keys:
        return []

    errors: list[ErrorInfo] = []
    matcher = SequenceMatcher(None, gt_keys, out_keys)

    for tag, i1, i2, j1, j2 in matcher.get_opcodes():
        if tag == "equal":
            continue
        elif tag == "replace":
            # Pair up substitutions
            gt_span = gt_keys[i1:i2]
            out_span = out_keys[j1:j2]
            for k in range(max(len(gt_span), len(out_span))):
                if k < len(gt_span) and k < len(out_span):
                    gp, gt_ = gt_span[k].split(":")
                    op, ot = out_span[k].split(":")
                    cat = classify_substitution(gp, op, gt_, ot)
                    if cat == "rhythm":
                        detail = f"{gt_span[k]} -> {out_span[k]}"
                    else:
                        detail = f"{gt_span[k]} -> {out_span[k]}"
                    errors.append(ErrorInfo(measure_num, staff_num, cat, detail))
                elif k < len(gt_span):
                    errors.append(ErrorInfo(measure_num, staff_num, "missing", gt_span[k]))
                else:
                    errors.append(ErrorInfo(measure_num, staff_num, "extra", out_span[k]))
        elif tag == "delete":
            for k in range(i1, i2):
                errors.append(ErrorInfo(measure_num, staff_num, "missing", gt_keys[k]))
        elif tag == "insert":
            for k in range(j1, j2):
                errors.append(ErrorInfo(measure_num, staff_num, "extra", out_keys[k]))

    return errors


def diagnose(gt_path: str, out_path: str) -> None:
    """Run full diagnostic comparison and print results."""
    gt_measures = extract_measures(gt_path)
    out_measures = extract_measures(out_path)

    gt_nums = {m.measure_num for m in gt_measures}
    out_nums = {m.measure_num for m in out_measures}
    overlap = sorted(gt_nums & out_nums)

    # --- Section 1: Coverage ---
    print("=" * 60)
    print("COVERAGE")
    print("=" * 60)
    if gt_nums:
        gt_range = f"{min(gt_nums)}-{max(gt_nums)}"
    else:
        gt_range = "(none)"
    if out_nums:
        out_range = f"{min(out_nums)}-{max(out_nums)}"
    else:
        out_range = "(none)"
    print(f"  Ground truth:  {len(gt_nums)} measures ({gt_range})")
    print(f"  Output:        {len(out_nums)} measures ({out_range})")
    print(f"  Overlap:       {len(overlap)} measures")
    if gt_nums:
        pct = 100 * len(overlap) / len(gt_nums)
        print(f"  Coverage:      {pct:.0f}%")
    print()

    if not overlap:
        print("No overlapping measures to compare.")
        return

    # Build lookup dicts
    gt_by_num = {m.measure_num: m for m in gt_measures}
    out_by_num = {m.measure_num: m for m in out_measures}

    # Collect all staves across both files
    all_staves: set[int] = set()
    for num in overlap:
        all_staves.update(gt_by_num[num].notes_by_staff.keys())
        all_staves.update(out_by_num[num].notes_by_staff.keys())

    # --- Section 2: Measure-by-measure diffs ---
    print("=" * 60)
    print("MEASURE-BY-MEASURE DIFFS (errors only)")
    print("=" * 60)

    all_errors: list[ErrorInfo] = []
    perfect_measures = 0
    compared_measures = 0

    for num in overlap:
        gt_m = gt_by_num[num]
        out_m = out_by_num[num]

